def score_neck(angle_deg: float, lateral_bending: bool = False) -> int:
    """Puntuación cuello - REBA"""
    if angle_deg <= 20:
        score = 1
    elif angle_deg <= 45:
        score = 2
    else:
        score = 3
    if lateral_bending:
        score += 1
    return score

def score_trunk(angle_deg: float, lateral_bending: bool = False, twisting: bool = False) -> int:
    """Puntuación tronco - REBA"""
    if angle_deg <= 5:
        score = 1
    elif angle_deg <= 20:
        score = 2
    elif angle_deg <= 60:
        score = 3
    else:
        score = 4
    if lateral_bending or twisting:
        score += 1
    return score

def score_legs(knee_angle: float, bilateral_weight: bool = True) -> int:
    """Puntuación piernas - REBA"""
    # Base: bipedestación bilateral
    score = 1 if bilateral_weight else 2
    # Flexión de rodilla
    if 30 < knee_angle <= 60:
        score += 1
    elif knee_angle > 60:
        score += 2
    return score

def score_upper_arm(angle_deg: float, shoulder_raised: bool = False, abducted: bool = False, gravity_assist: bool = False) -> int:
    """Puntuación brazo - REBA"""
    if angle_deg <= 20:
        score = 1
    elif angle_deg <= 45:
        score = 2
    elif angle_deg <= 90:
        score = 3
    else:
        score = 4
    if shoulder_raised:
        score += 1
    if abducted:
        score += 1
    if gravity_assist:
        score -= 1
    return max(1, score)

def score_forearm(angle_deg: float) -> int:
    """Puntuación antebrazo - REBA"""
    if 60 <= angle_deg <= 100:
        return 1
    return 2

def score_wrist(angle_deg: float, lateral_deviation: bool = False) -> int:
    """Puntuación muñeca - REBA"""
    score = 1 if angle_deg <= 15 else 2
    if lateral_deviation:
        score += 1
    return score

# Tables REBA
TABLE_A = [
    # neck=1
    [[1, 2, 3, 4], [1, 2, 3, 4], [3, 3, 5, 6]],
    # neck=2
    [[2, 3, 4, 5], [3, 4, 5, 6], [4, 5, 6, 7]],
    # neck=3
    [[2, 4, 5, 6], [4, 5, 6, 7], [5, 6, 7, 8]],
]
# rows=trunk(1-4 clamped to 0-3), cols=leg(1-4)

TABLE_B = [
    # forearm=1
    [[1, 2, 2], [1, 2, 3]],
    # forearm=2
    [[1, 2, 3], [2, 3, 4]],
]
# rows=forearm(1-2), sub-rows=wrist(1-2), cols=upper_arm(1-3 clamped)

TABLE_C = [
    [1, 1, 1, 2, 3, 3, 4, 5, 6, 7, 7, 7],
    [1, 2, 2, 3, 4, 4, 5, 6, 6, 7, 7, 8],
    [2, 3, 3, 3, 4, 5, 6, 7, 7, 8, 8, 8],
    [3, 4, 4, 4, 5, 6, 7, 8, 8, 9, 9, 9],
    [4, 4, 4, 5, 6, 7, 8, 8, 9, 9, 9, 9],
    [6, 6, 6, 7, 8, 8, 9, 9,10,10,10,10],
    [7, 7, 7, 8, 9, 9, 9,10,10,11,11,11],
    [8, 8, 8, 9,10,10,10,10,10,11,11,11],
    [9, 9, 9,10,10,10,11,11,11,12,12,12],
    [10,10,10,11,11,11,11,12,12,12,12,12],
    [11,11,11,11,12,12,12,12,12,12,12,12],
    [12,12,12,12,12,12,12,12,12,12,12,12],
]

def lookup_table_a(trunk: int, neck: int, legs: int) -> int:
    t = min(max(trunk-1, 0), 3)
    n = min(max(neck-1, 0), 2)
    l = min(max(legs-1, 0), 3)
    if n < len(TABLE_A) and t < len(TABLE_A[n]) and l < len(TABLE_A[n][t]):
        return TABLE_A[n][t][l]
    return 6

def lookup_table_b(upper_arm: int, forearm: int, wrist: int) -> int:
    fa = min(max(forearm-1, 0), 1)
    wr = min(max(wrist-1, 0), 1)
    ua = min(max(upper_arm-1, 0), 2)
    if fa < len(TABLE_B) and wr < len(TABLE_B[fa]) and ua < len(TABLE_B[fa][wr]):
        return TABLE_B[fa][wr][ua]
    return 4

def lookup_table_c(score_a: int, score_b: int) -> int:
    r = min(max(score_a-1, 0), 11)
    c = min(max(score_b-1, 0), 11)
    return TABLE_C[r][c]

def reba_action_level(score: int) -> dict:
    if score == 1:
        return {'nivel': 'INAPRECIABLE', 'accion': 'No necesaria', 'color': '#27ae60', 'badge': 'success'}
    elif score <= 3:
        return {'nivel': 'BAJO', 'accion': 'Puede ser necesaria', 'color': '#f39c12', 'badge': 'warning'}
    elif score <= 7:
        return {'nivel': 'MEDIO', 'accion': 'Necesaria', 'color': '#e67e22', 'badge': 'orange'}
    elif score <= 10:
        return {'nivel': 'ALTO', 'accion': 'Necesaria pronto', 'color': '#e74c3c', 'badge': 'danger'}
    else:
        return {'nivel': 'MUY ALTO', 'accion': 'Inmediata', 'color': '#8e44ad', 'badge': 'critical'}

def calculate_reba(data: dict) -> dict:
    """
    Calculate full REBA score from form data
    data keys: neck_angle, trunk_angle, leg_knee_angle, upper_arm_angle,
               forearm_angle, wrist_angle + booleans
    """
    # Scores individuales
    neck = score_neck(data.get('neck_angle', 15),
                      data.get('neck_lateral', False))
    trunk = score_trunk(data.get('trunk_angle', 10),
                        data.get('trunk_lateral', False),
                        data.get('trunk_twist', False))
    legs = score_legs(data.get('leg_knee_angle', 175),
                      data.get('bilateral_weight', True))

    upper_arm = score_upper_arm(data.get('upper_arm_angle', 20),
                                data.get('shoulder_raised', False),
                                data.get('arm_abducted', False),
                                data.get('gravity_assist', False))
    forearm = score_forearm(data.get('forearm_angle', 90))
    wrist = score_wrist(data.get('wrist_angle', 10),
                        data.get('wrist_lateral', False))

    # Force load
    force_score = data.get('force_score', 0)  # 0,1,2
    coupling_score = data.get('coupling_score', 0)  # 0,1,2,3
    activity_score = data.get('activity_score', 0)  # 0,1,2,3

    # Table lookups
    score_a = lookup_table_a(trunk, neck, legs)
    score_a_force = min(score_a + force_score, 12)

    score_b = lookup_table_b(upper_arm, forearm, wrist)
    score_b_coupling = min(score_b + coupling_score, 12)

    score_c = lookup_table_c(score_a_force, score_b_coupling)
    final_score = min(score_c + activity_score, 15)

    action = reba_action_level(final_score)

    return {
        'neck': neck, 'trunk': trunk, 'legs': legs,
        'upper_arm': upper_arm, 'forearm': forearm, 'wrist': wrist,
        'score_a': score_a, 'score_a_force': score_a_force,
        'score_b': score_b, 'score_b_coupling': score_b_coupling,
        'score_c': score_c, 'final_score': final_score,
        'nivel': action['nivel'],
        'accion': action['accion'],
        'color': action['color'],
        'badge': action['badge'],
        'force_score': force_score,
        'coupling_score': coupling_score,
        'activity_score': activity_score,
    }

