LEST_NIVEL = [
    (2, 'Satisfactorio', '#27ae60'),
    (4, 'Débilmente molesto', '#2ecc71'),
    (5, 'Medianamente molesto', '#f39c12'),
    (6, 'Muy molesto', '#e67e22'),
    (8, 'Nocivo a largo plazo', '#e74c3c'),
    (10, 'Nocivo a corto plazo', '#8e44ad'),
]

def lest_nivel(score: float) -> dict:
    for threshold, label, color in LEST_NIVEL:
        if score <= threshold:
            return {'label': label, 'color': color, 'score': round(score, 1)}
    return {'label': 'Nocivo a corto plazo', 'color': '#8e44ad', 'score': round(score, 1)}

def calculate_lest(data: dict) -> dict:
    """
    Calculate LEST scores for all 5 dimensions
    Returns per-dimension and global score
    """
    results = {}

    # 1. CARGA FÍSICA (postura, esfuerzo, manipulación)
    postura_score = data.get('lest_postura', 3)
    esfuerzo_score = data.get('lest_esfuerzo', 3)
    manipulacion_score = data.get('lest_manipulacion', 2)
    carga_fisica = (postura_score + esfuerzo_score + manipulacion_score) / 3
    results['carga_fisica'] = {'score': round(carga_fisica, 2), **lest_nivel(carga_fisica)}

    # 2. ENTORNO FÍSICO (temperatura, ruido, iluminación, vibraciones)
    temp_score = data.get('lest_temperatura', 2)
    ruido_score = data.get('lest_ruido', 2)
    ilum_score = data.get('lest_iluminacion', 2)
    vib_score = data.get('lest_vibraciones', 1)
    entorno = (temp_score + ruido_score + ilum_score + vib_score) / 4
    results['entorno'] = {'score': round(entorno, 2), **lest_nivel(entorno)}

    # 3. CARGA MENTAL (atención, complejidad, minuciosidad)
    atencion_score = data.get('lest_atencion', 3)
    complejidad_score = data.get('lest_complejidad', 2)
    minuciosidad_score = data.get('lest_minuciosidad', 2)
    carga_mental = (atencion_score + complejidad_score + minuciosidad_score) / 3
    results['carga_mental'] = {'score': round(carga_mental, 2), **lest_nivel(carga_mental)}

    # 4. ASPECTOS PSICOSOCIALES (iniciativa, comunicación, relaciones, cooperación)
    iniciativa_score = data.get('lest_iniciativa', 2)
    comunicacion_score = data.get('lest_comunicacion', 2)
    relaciones_score = data.get('lest_relaciones', 2)
    cooperacion_score = data.get('lest_cooperacion', 2)
    psicosocial = (iniciativa_score + comunicacion_score + relaciones_score + cooperacion_score) / 4
    results['psicosocial'] = {'score': round(psicosocial, 2), **lest_nivel(psicosocial)}

    # 5. TIEMPO DE TRABAJO (pausas, trabajo nocturno, horario)
    pausas_score = data.get('lest_pausas', 2)
    horario_score = data.get('lest_horario', 2)
    rotacion_score = data.get('lest_rotacion', 1)
    ritmo_score = data.get('lest_ritmo', 3)
    tiempo_trabajo = (pausas_score + horario_score + rotacion_score + ritmo_score) / 4
    results['tiempo_trabajo'] = {'score': round(tiempo_trabajo, 2), **lest_nivel(tiempo_trabajo)}

    # GLOBAL LEST (weighted by Ley Silla priority)
    # Carga física y tiempo de trabajo tienen mayor peso por la Ley Silla
    global_score = (
        carga_fisica * 0.30 +
        entorno * 0.15 +
        carga_mental * 0.15 +
        psicosocial * 0.15 +
        tiempo_trabajo * 0.25
    )
    global_nivel = lest_nivel(global_score)
    results['global'] = {'score': round(global_score, 2), **global_nivel}

    return results

