# LEY SILLA - DIAGRAMA 7 PREGUNTAS + NIVEL DE RIESGO
# ═══════════════════════════════════════════════════════════════════════════════

def evaluar_ley_silla(data: dict) -> dict:
    """
    Evaluación según DOF 17/07/2025 - Disposiciones Ley Silla
    7 preguntas condicionales → tipo bipedestación → nivel riesgo → tipo silla
    """
    # P1: ¿Cuánto tiempo permanece de pie sin moverse? (horas)
    tiempo_pie = data.get('tiempo_pie', 0)  # horas
    # P2: ¿Tiene espacio para desplazarse?
    espacio_desplazamiento = data.get('espacio_desplazamiento', True)
    # P3: ¿Puede cambiar de postura durante la jornada?
    puede_cambiar_postura = data.get('puede_cambiar_postura', True)
    # P4: ¿Ha reportado molestias musculoesqueléticas?
    molestias_reportadas = data.get('molestias_reportadas', False)
    # P5: ¿Tipo de superficie de trabajo?
    tipo_superficie = data.get('tipo_superficie', 'concreto')  # concreto, madera, alfombra, metal
    # P6: ¿Usa calzado adecuado?
    calzado_adecuado = data.get('calzado_adecuado', True)
    # P7: ¿Cuenta con pausas de descanso?
    tiene_pausas = data.get('tiene_pausas', True)

    # ── Clasificación de bipedestación ────────────────────────────────────────
    if not espacio_desplazamiento and tiempo_pie >= 1:
        tipo = 'ESTÁTICA'
        tipo_desc = 'Postura de pie prácticamente sin moverse o con desplazamientos mínimos'
    elif espacio_desplazamiento:
        tipo = 'DINÁMICA'
        tipo_desc = 'Postura de pie con posibilidad de realizar desplazamientos amplios'
    else:
        tipo = 'DINÁMICA'
        tipo_desc = 'Postura de pie con desplazamientos variables'

    if tiempo_pie >= 3:
        tipo = tipo + ' PROLONGADA'
        tipo_desc += ' — más de 3 horas continuas (PROLONGADA)'

    # ── Cálculo de nivel de riesgo ────────────────────────────────────────────
    puntos_riesgo = 0

    # Tiempo de pie
    if tiempo_pie >= 6:
        puntos_riesgo += 4
    elif tiempo_pie >= 3:
        puntos_riesgo += 3
    elif tiempo_pie >= 1:
        puntos_riesgo += 1

    # Sin posibilidad de cambio postural
    if not puede_cambiar_postura:
        puntos_riesgo += 2

    # Sin espacio de desplazamiento
    if not espacio_desplazamiento:
        puntos_riesgo += 1

    # Molestias reportadas
    if molestias_reportadas:
        puntos_riesgo += 2

    # Superficie de trabajo
    superficie_riesgo = {
        'concreto': 2, 'metal': 2, 'ceramica': 2,
        'madera': 1, 'alfombra': 0, 'goma': 0, 'antifatiga': -1
    }
    puntos_riesgo += superficie_riesgo.get(tipo_superficie, 1)

    # Calzado inadecuado
    if not calzado_adecuado:
        puntos_riesgo += 1

    # Sin pausas de descanso
    if not tiene_pausas:
        puntos_riesgo += 2

    # ── Nivel de riesgo final ─────────────────────────────────────────────────
    if puntos_riesgo <= 2:
        nivel_riesgo = 'BAJO'
        color_riesgo = '#27ae60'
        tipo_asiento = 'Banco alto o taburete sin respaldo'
        descripcion_riesgo = 'Riesgo aceptable. Proveer asiento o banco alto para pausas.'
    elif puntos_riesgo <= 5:
        nivel_riesgo = 'MEDIO'
        color_riesgo = '#f39c12'
        tipo_asiento = 'Silla alta con respaldo medio o banco ergonómico'
        descripcion_riesgo = 'Riesgo moderado. Proveer silla con respaldo en puesto o área de descanso cercana.'
    else:
        nivel_riesgo = 'ALTO'
        color_riesgo = '#e74c3c'
        tipo_asiento = 'Silla ergonómica ajustable con soporte lumbar y reposabrazos'
        descripcion_riesgo = 'Riesgo elevado. Proveer silla ergonómica en puesto de trabajo. Implementar pausas activas y rediseño del puesto.'

    # ── Medidas preventivas recomendadas (Disposiciones, art. 5to) ────────────
    medidas = []
    if not tiene_pausas:
        medidas.append('Implementar programa de pausas activas cada 60-90 minutos')
    if not calzado_adecuado:
        medidas.append('Proporcionar o exigir calzado ergonómico con soporte de arco')
    if tipo_superficie in ['concreto', 'metal', 'ceramica']:
        medidas.append('Colocar superficies antifatiga (tapetes ergonómicos) en el área de trabajo')
    if not puede_cambiar_postura:
        medidas.append('Rediseñar el puesto para permitir alternancia entre postura sentado/parado')
    if molestias_reportadas:
        medidas.append('Canalizar al trabajador a atención médica por molestias reportadas (Disposiciones, inciso J)')
    if tiempo_pie >= 3:
        medidas.append('Establecer rotación de tareas o cambios de actividad cada hora')
    medidas.append('Registrar la evaluación en actas de la Comisión de Seguridad e Higiene (NOM-030-STPS-2009)')
    medidas.append('Informar al trabajador sobre los riesgos de bipedestación y medidas preventivas')

    return {
        'tipo_bipedestacion': tipo,
        'tipo_desc': tipo_desc,
        'nivel_riesgo': nivel_riesgo,
        'color_riesgo': color_riesgo,
        'puntos_riesgo': puntos_riesgo,
        'tipo_asiento_recomendado': tipo_asiento,
        'descripcion_riesgo': descripcion_riesgo,
        'medidas_preventivas': medidas,
        'inputs': {
            'tiempo_pie': tiempo_pie,
            'espacio_desplazamiento': espacio_desplazamiento,
            'puede_cambiar_postura': puede_cambiar_postura,
            'molestias_reportadas': molestias_reportadas,
            'tipo_superficie': tipo_superficie,
            'calzado_adecuado': calzado_adecuado,
            'tiene_pausas': tiene_pausas,
        }
    }

def get_recomendaciones_integrales(reba_result: dict, lest_result: dict, ley_silla_result: dict) -> list:
    """Genera recomendaciones integradas REBA + LEST + Ley Silla"""
    recs = []

    reba_score = reba_result.get('final_score', 1)
    lest_global = lest_result.get('global', {}).get('score', 0)
    nivel_silla = ley_silla_result.get('nivel_riesgo', 'BAJO')

    # Recomendaciones REBA
    if reba_score >= 8:
        recs.append({'tipo': 'URGENTE', 'fuente': 'REBA',
                     'texto': f'REBA Score {reba_score}: Intervención ergonómica INMEDIATA requerida. Rediseño completo del puesto.'})
    elif reba_score >= 4:
        recs.append({'tipo': 'IMPORTANTE', 'fuente': 'REBA',
                     'texto': f'REBA Score {reba_score}: Mejorar postura de cuello, tronco y extremidades. Capacitar al trabajador.'})

    # Recomendaciones LEST por dimensión
    cf = lest_result.get('carga_fisica', {}).get('score', 0)
    if cf >= 6:
        recs.append({'tipo': 'URGENTE', 'fuente': 'LEST',
                     'texto': f'Carga Física LEST ({cf}/10): Rediseñar puesto. Implementar ayudas mecánicas o rotación de tareas.'})
    tt = lest_result.get('tiempo_trabajo', {}).get('score', 0)
    if tt >= 5:
        recs.append({'tipo': 'IMPORTANTE', 'fuente': 'LEST',
                     'texto': f'Tiempo de Trabajo LEST ({tt}/10): Establecer pausas reglamentarias. Revisar jornada y horarios (Ley Silla, art. 5to).'})
    ent = lest_result.get('entorno', {}).get('score', 0)
    if ent >= 5:
        recs.append({'tipo': 'RECOMENDADO', 'fuente': 'LEST',
                     'texto': f'Entorno Físico LEST ({ent}/10): Corregir condiciones de temperatura, iluminación o ruido.'})

    # Recomendaciones Ley Silla
    for medida in ley_silla_result.get('medidas_preventivas', []):
        recs.append({'tipo': 'LEY SILLA', 'fuente': 'DOF 17/07/2025',
                     'texto': medida})

    # Silla recomendada
    recs.append({'tipo': 'SILLA', 'fuente': 'LEY SILLA',
                 'texto': f"Asiento recomendado: {ley_silla_result.get('tipo_asiento_recomendado', 'Silla ergonómica')}"})

    return recs


