# ─── DOCX ─────────────────────────────────────────────────────────────────────

def generate_docx(ev: dict) -> str:
    from docx import Document
    from docx.shared import Pt, Cm, RGBColor
    from docx.enum.text import WD_ALIGN_PARAGRAPH
    from docx.enum.table import WD_TABLE_ALIGNMENT
    from docx.oxml.ns import qn
    from docx.oxml import OxmlElement
    import copy

    filename = REPORTS_DIR / f"reba_lest_{ev['uuid'][:8]}.docx"
    doc = Document()

    # Page margins
    section = doc.sections[0]
    section.top_margin = Cm(2)
    section.bottom_margin = Cm(2)
    section.left_margin = Cm(2.5)
    section.right_margin = Cm(2.5)

    def add_heading(text, level=1, color_hex='1a3a5c'):
        p = doc.add_heading(text, level=level)
        run = p.runs[0] if p.runs else p.add_run(text)
        r, g, b = int(color_hex[0:2], 16), int(color_hex[2:4], 16), int(color_hex[4:6], 16)
        run.font.color.rgb = RGBColor(r, g, b)
        return p

    def add_kv_table(rows, col_widths_cm=None):
        table = doc.add_table(rows=len(rows), cols=2)
        table.style = 'Table Grid'
        for i, (k, v) in enumerate(rows):
            cells = table.rows[i].cells
            cells[0].text = k
            cells[1].text = str(v)
            cells[0].paragraphs[0].runs[0].bold = True
        return table

    # Title
    title_p = doc.add_paragraph()
    title_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    run = title_p.add_run('REPORTE DE EVALUACIÓN ERGONÓMICA')
    run.bold = True
    run.font.size = Pt(16)
    run.font.color.rgb = RGBColor(26, 58, 92)

    sub_p = doc.add_paragraph()
    sub_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
    sub_run = sub_p.add_run('Métodos REBA + LEST | Ley Silla DOF 17/07/2025 | STPS México')
    sub_run.font.size = Pt(10)
    sub_run.font.color.rgb = RGBColor(93, 109, 126)

    doc.add_paragraph()

    # 1. Datos generales
    add_heading('1. Datos Generales')
    gen_rows = [
        ('Trabajador:', ev.get('trabajador', '-')),
        ('Puesto:', ev.get('puesto', '-')),
        ('Área:', ev.get('area', '-')),
        ('Empresa:', ev.get('empresa', '-')),
        ('Fecha:', ev.get('fecha', '-')),
        ('Folio:', ev.get('uuid', '-')[:12]),
    ]
    add_kv_table(gen_rows)

    doc.add_paragraph()
    add_heading('2. Evaluación Ley Silla (DOF 17/07/2025)')
    ls = ev.get('ley_silla_data', {})
    ls_rows = [
        ('Tipo de Bipedestación:', ev.get('tipo_bipedestacion', '-')),
        ('Nivel de Riesgo:', ev.get('nivel_riesgo_ley_silla', '-')),
        ('Asiento Recomendado:', ls.get('tipo_asiento_recomendado', '-')),
        ('Tiempo en Pie (hrs):', str(ls.get('inputs', {}).get('tiempo_pie', '-'))),
        ('Tipo de Superficie:', str(ls.get('inputs', {}).get('tipo_superficie', '-')).capitalize()),
    ]
    add_kv_table(ls_rows)

    doc.add_paragraph()
    add_heading('3. Resultados REBA')
    reba = ev.get('reba_data', {})
    reba_rows = [
        ('Score Final REBA:', str(ev.get('reba_score', '-'))),
        ('Nivel de Riesgo REBA:', ev.get('reba_nivel', '-')),
        ('Acción Recomendada:', reba.get('accion', '-')),
        ('Puntuación Cuello:', str(reba.get('neck', '-'))),
        ('Puntuación Tronco:', str(reba.get('trunk', '-'))),
        ('Puntuación Piernas:', str(reba.get('legs', '-'))),
        ('Score Grupo A:', str(reba.get('score_a', '-'))),
        ('Score Grupo B:', str(reba.get('score_b', '-'))),
        ('Score Tabla C:', str(reba.get('score_c', '-'))),
    ]
    add_kv_table(reba_rows)

    doc.add_paragraph()
    add_heading('4. Resultados LEST')
    lest = ev.get('lest_data', {})
    lest_rows = [
        ('Carga Física:', f"{lest.get('carga_fisica', {}).get('score', '-')} / 10 — {lest.get('carga_fisica', {}).get('label', '-')}"),
        ('Entorno Físico:', f"{lest.get('entorno', {}).get('score', '-')} / 10 — {lest.get('entorno', {}).get('label', '-')}"),
        ('Carga Mental:', f"{lest.get('carga_mental', {}).get('score', '-')} / 10 — {lest.get('carga_mental', {}).get('label', '-')}"),
        ('Aspectos Psicosociales:', f"{lest.get('psicosocial', {}).get('score', '-')} / 10 — {lest.get('psicosocial', {}).get('label', '-')}"),
        ('Tiempo de Trabajo:', f"{lest.get('tiempo_trabajo', {}).get('score', '-')} / 10 — {lest.get('tiempo_trabajo', {}).get('label', '-')}"),
        ('PUNTUACIÓN GLOBAL:', f"{lest.get('global', {}).get('score', '-')} / 10 — {lest.get('global', {}).get('label', '-')}"),
    ]
    add_kv_table(lest_rows)

    doc.add_paragraph()
    add_heading('5. Recomendaciones Integrales')
    recs = ev.get('recomendaciones', [])
    for r in recs:
        p = doc.add_paragraph(style='List Bullet')
        run_tipo = p.add_run(f"[{r.get('tipo','')}] ")
        run_tipo.bold = True
        p.add_run(r.get('texto', ''))

    doc.add_paragraph()
    doc.add_paragraph('_' * 40 + '     ' + '_' * 40)
    sig_p = doc.add_paragraph()
    sig_p.add_run('Firma del Evaluador').bold = True
    sig_p.add_run('                                        ')
    sig_p.add_run('Firma del Trabajador').bold = True

    doc.add_paragraph()
    note = doc.add_paragraph()
    note_run = note.add_run(
        'Documento generado conforme a las DISPOSICIONES sobre factores de riesgo de trabajo '
        'para garantizar el derecho al descanso durante la jornada laboral de personas '
        'trabajadoras en bipedestación. DOF 17/07/2025. STPS México.')
    note_run.font.size = Pt(8)
    note_run.font.color.rgb = RGBColor(127, 140, 141)

    doc.save(str(filename))
    return str(filename)

# ─── XLSX ─────────────────────────────────────────────────────────────────────

def generate_xlsx(ev: dict) -> str:
    from openpyxl import Workbook
    from openpyxl.styles import (Font, PatternFill, Alignment, Border,
                                  Side, GradientFill)
    from openpyxl.utils import get_column_letter

    filename = REPORTS_DIR / f"reba_lest_{ev['uuid'][:8]}.xlsx"
    wb = Workbook()

    DARK = "1A3A5C"
    ACCENT = "E67E22"
    LIGHT = "D5E8F0"
    GREEN = "27AE60"
    YELLOW = "F39C12"
    RED = "E74C3C"
    WHITE = "FFFFFF"

    def header_style(cell, bg=DARK, fg=WHITE, bold=True, size=11):
        cell.font = Font(bold=bold, color=fg, size=size)
        cell.fill = PatternFill("solid", fgColor=bg)
        cell.alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)

    def data_style(cell, bg=WHITE, bold=False, align='left'):
        cell.font = Font(bold=bold, size=10)
        cell.fill = PatternFill("solid", fgColor=bg)
        cell.alignment = Alignment(horizontal=align, vertical='center', wrap_text=True)

    thin = Side(style='thin', color='BDC3C7')
    border = Border(left=thin, right=thin, top=thin, bottom=thin)

    def set_border(cell):
        cell.border = border

    # ── SHEET 1: Resumen ──────────────────────────────────────────────────────
    ws1 = wb.active
    ws1.title = "Resumen Ejecutivo"
    ws1.column_dimensions['A'].width = 28
    ws1.column_dimensions['B'].width = 35
    ws1.column_dimensions['C'].width = 20
    ws1.column_dimensions['D'].width = 30
    ws1.row_dimensions[1].height = 35

    # Header
    ws1.merge_cells('A1:D1')
    ws1['A1'] = 'EVALUACIÓN ERGONÓMICA — LEY SILLA DOF 17/07/2025'
    header_style(ws1['A1'], size=13)
    ws1.merge_cells('A2:D2')
    ws1['A2'] = f"Folio: {ev['uuid'][:8].upper()} | Fecha: {ev.get('fecha', '-')} | Empresa: {ev.get('empresa', '-')}"
    header_style(ws1['A2'], bg=ACCENT, size=10)

    row = 4
    sections = [
        ('DATOS DEL TRABAJADOR', [
            ('Nombre', ev.get('trabajador', '-')),
            ('Puesto', ev.get('puesto', '-')),
            ('Área', ev.get('area', '-')),
        ]),
        ('LEY SILLA', [
            ('Tipo Bipedestación', ev.get('tipo_bipedestacion', '-')),
            ('Nivel de Riesgo', ev.get('nivel_riesgo_ley_silla', '-')),
            ('Silla Recomendada', ev.get('ley_silla_data', {}).get('tipo_asiento_recomendado', '-')),
        ]),
        ('REBA', [
            ('Score Final', str(ev.get('reba_score', '-'))),
            ('Nivel REBA', ev.get('reba_nivel', '-')),
            ('Acción', ev.get('reba_data', {}).get('accion', '-')),
        ]),
        ('LEST GLOBAL', [
            ('Puntuación Global', str(ev.get('lest_global', '-'))),
            ('Nivel LEST', ev.get('lest_nivel', '-')),
            ('Carga Física', str(ev.get('lest_carga_fisica', '-'))),
        ]),
    ]

    for section_title, items in sections:
        ws1.merge_cells(f'A{row}:D{row}')
        ws1[f'A{row}'] = section_title
        header_style(ws1[f'A{row}'], bg=DARK)
        row += 1
        for k, v in items:
            ws1[f'A{row}'] = k
            ws1[f'B{row}'] = v
            data_style(ws1[f'A{row}'], bg=LIGHT, bold=True)
            data_style(ws1[f'B{row}'])
            set_border(ws1[f'A{row}'])
            set_border(ws1[f'B{row}'])
            row += 1
        row += 1

    # ── SHEET 2: REBA Detalle ─────────────────────────────────────────────────
    ws2 = wb.create_sheet("REBA Detalle")
    ws2.column_dimensions['A'].width = 30
    ws2.column_dimensions['B'].width = 20
    ws2.column_dimensions['C'].width = 40

    reba = ev.get('reba_data', {})
    ws2.merge_cells('A1:C1')
    ws2['A1'] = 'MÉTODO REBA — RAPID ENTIRE BODY ASSESSMENT'
    header_style(ws2['A1'], size=12)

    reba_details = [
        ('Campo', 'Valor', 'Descripción'),
        ('Puntuación Cuello', reba.get('neck', '-'), 'Flexión/extensión cervical'),
        ('Puntuación Tronco', reba.get('trunk', '-'), 'Flexión/extensión lumbar'),
        ('Puntuación Piernas', reba.get('legs', '-'), 'Carga sobre extremidades inferiores'),
        ('Score Grupo A', reba.get('score_a', '-'), 'Combinación cuello+tronco+piernas'),
        ('Fuerza/Carga', reba.get('force_score', '-'), 'Factor de carga/fuerza'),
        ('Score A+Fuerza', reba.get('score_a_force', '-'), 'Grupo A ajustado'),
        ('Puntuación Brazo', reba.get('upper_arm', '-'), 'Flexión del brazo'),
        ('Puntuación Antebrazo', reba.get('forearm', '-'), 'Flexión del codo'),
        ('Puntuación Muñeca', reba.get('wrist', '-'), 'Flexión/desviación de muñeca'),
        ('Score Grupo B', reba.get('score_b', '-'), 'Combinación brazo+antebrazo+muñeca'),
        ('Acoplamiento', reba.get('coupling_score', '-'), 'Tipo de agarre'),
        ('Score B+Acoplamiento', reba.get('score_b_coupling', '-'), 'Grupo B ajustado'),
        ('Score Tabla C', reba.get('score_c', '-'), 'Combinación A+B'),
        ('Actividad', reba.get('activity_score', '-'), 'Tipo de actividad'),
        ('SCORE FINAL REBA', ev.get('reba_score', '-'), '→ Nivel de acción'),
        ('NIVEL DE RIESGO', ev.get('reba_nivel', '-'), reba.get('accion', '-')),
    ]

    for i, row_data in enumerate(reba_details):
        for j, val in enumerate(row_data):
            cell = ws2.cell(row=i+2, column=j+1, value=str(val) if val is not None else '-')
            if i == 0:
                header_style(cell, bg='2C3E50')
            elif i >= len(reba_details) - 2:
                header_style(cell, bg=ACCENT)
            else:
                data_style(cell, bg=WHITE if i % 2 == 0 else LIGHT)
            set_border(cell)

    # ── SHEET 3: LEST Detalle ─────────────────────────────────────────────────
    ws3 = wb.create_sheet("LEST Detalle")
    ws3.column_dimensions['A'].width = 30
    ws3.column_dimensions['B'].width = 15
    ws3.column_dimensions['C'].width = 30
    ws3.column_dimensions['D'].width = 20

    lest = ev.get('lest_data', {})
    ws3.merge_cells('A1:D1')
    ws3['A1'] = 'MÉTODO LEST — EVALUACIÓN GLOBAL DEL PUESTO'
    header_style(ws3['A1'], size=12)

    headers = ['Dimensión', 'Puntuación (0-10)', 'Nivel', 'Interpretación']
    for j, h in enumerate(headers):
        cell = ws3.cell(row=2, column=j+1, value=h)
        header_style(cell, bg='2C3E50')
        set_border(cell)

    lest_dims = [
        ('Carga Física', lest.get('carga_fisica', {}), 'Postura, esfuerzo, manipulación'),
        ('Entorno Físico', lest.get('entorno', {}), 'Temperatura, ruido, iluminación'),
        ('Carga Mental', lest.get('carga_mental', {}), 'Atención, complejidad, minuciosidad'),
        ('Aspectos Psicosociales', lest.get('psicosocial', {}), 'Iniciativa, comunicación, relaciones'),
        ('Tiempo de Trabajo', lest.get('tiempo_trabajo', {}), 'Pausas, horario, ritmo, rotación'),
        ('GLOBAL (Ponderado)', lest.get('global', {}), 'Resultado integral del puesto'),
    ]

    for i, (name, dim, interp) in enumerate(lest_dims):
        row_num = i + 3
        bg = LIGHT if i % 2 == 0 else WHITE
        if name.startswith('GLOBAL'):
            bg = DARK

        vals = [name, dim.get('score', '-'), dim.get('label', '-'), interp]
        for j, val in enumerate(vals):
            cell = ws3.cell(row=row_num, column=j+1, value=str(val))
            if name.startswith('GLOBAL'):
                header_style(cell, bg=DARK)
            else:
                data_style(cell, bg=bg, bold=(j == 0))
            set_border(cell)

    wb.save(str(filename))
    return str(filename)



