@app.route('/api/report/<eu>/<fmt>')
@login_required
def gen_report(eu, fmt):
    db = get_db()
    ev = db.execute('SELECT * FROM evaluaciones WHERE uuid=? AND user_id=?', (eu, session['user_id'])).fetchone()
    db.close()
    if not ev: return jsonify({'error': 'Not found'}), 404
    d = dict(ev); d['evaluador'] = session.get('evaluador','')
    for f in ['reba_data','lest_data','ley_silla_data','angulos_data','recomendaciones']:
        if d.get(f):
            try: d[f] = json.loads(d[f])
            except: pass
    if fmt == 'pdf': return send_file(generate_pdf(d), as_attachment=True, download_name=f"eval_{eu[:8]}.pdf")
    elif fmt == 'docx': return send_file(generate_docx(d), as_attachment=True, download_name=f"eval_{eu[:8]}.docx")
    elif fmt == 'xlsx': return send_file(generate_xlsx(d), as_attachment=True, download_name=f"eval_{eu[:8]}.xlsx")
    return jsonify({'error': 'Bad format'}), 400

